Infraestrutura como codigo para load-balancer - BioResearch Labs - api-gateway-deployment:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "uk-london-1"
}

resource "oci_load_balancer_load_balancer" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "load-balancer-shared-services-054"

  # configuração específica
  shape          = "VM.Standard.E4.Flex"

  tags = {
    project     = "BioResearch Labs - api-gateway-deployment"
    environment = "shared-services"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment shared-services"
}

output "resource_id" {
  value = oci_load_balancer_load_balancer.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "uk-london-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**configuração:**
- Compartment: `shared-services`
- Region: `uk-london-1`
- Shape: `VM.Standard.E4.Flex`
- OCPUs: `48`
- Storage: `50 GB`

documentação: https://registry.terraform.io/providers/oracle/oci/latest/docs

